export function Icon({
  name,
  size = 16,
  className,
  title,
}: {
  name: IconName
  size?: number
  className?: string
  title?: string
}) {
  const cls = className ? `ri ${className}` : 'ri'
  if (name === 'chevron-down' || name === 'chevron-up') {
    const points = name === 'chevron-down' ? '15.25 6.5 9 12.75 2.75 6.5' : '2.75 11.5 9 5.25 15.25 11.5'
    return (
      <svg width={size} height={size} viewBox="0 0 18 18" fill="none" className={cls} aria-hidden={title ? undefined : true}>
        {title && <title>{title}</title>}
        <polyline points={points} fill="none" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" />
      </svg>
    )
  }
  if (STROKE_ICONS.has(name)) {
    return (
      <svg width={size} height={size} viewBox="0 0 24 24" fill="none" className={cls} aria-hidden={title ? undefined : true}>
        {title && <title>{title}</title>}
        {PATHS[name]}
      </svg>
    )
  }
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="currentColor" className={cls} aria-hidden={title ? undefined : true}>
      {title && <title>{title}</title>}
      {PATHS[name]}
    </svg>
  )
}
